const data = $input.first().json;
const input = $('Normalize Input').first().json;

let candidate = data;
if (Array.isArray(data)) candidate = data[0];
if (data?.data && Array.isArray(data.data)) candidate = data.data[0];
if (data?.candidates && Array.isArray(data.candidates)) candidate = data.candidates[0];
if (data?.content && Array.isArray(data.content)) candidate = data.content[0];
if (data?.items && Array.isArray(data.items)) candidate = data.items[0];

if (!candidate) {
  throw new Error(
    'No MCQ candidate found for email=' + input.email +
    ' scheduleId=' + input.testScheduleId +
    '. Raw: ' + JSON.stringify(data).slice(0, 800)
  );
}

const scoreFields = [
  'score', 'totalScore', 'percentage', 'marks', 'mcqScore',
  'testScore', 'overallScore', 'finalScore', 'obtainedMarks',
  'totalMarks', 'percentile'
];

let mcq_score = null;
let score_field = null;

for (const field of scoreFields) {
  if (candidate[field] != null && candidate[field] !== '') {
    mcq_score = Number(candidate[field]);
    score_field = field;
    break;
  }
}

if (mcq_score == null && candidate.result?.score != null) {
  mcq_score = Number(candidate.result.score);
  score_field = 'result.score';
}
if (mcq_score == null && candidate.testResult?.score != null) {
  mcq_score = Number(candidate.testResult.score);
  score_field = 'testResult.score';
}
if (mcq_score == null && candidate.obtainedMarks != null && candidate.totalMarks != null) {
  mcq_score = (Number(candidate.obtainedMarks) / Number(candidate.totalMarks)) * 100;
  score_field = 'obtainedMarks/totalMarks';
}

if (mcq_score == null || Number.isNaN(mcq_score)) {
  throw new Error(
    'MCQ score field not found. Keys: ' + Object.keys(candidate).join(', ') +
    ' Raw: ' + JSON.stringify(candidate).slice(0, 800)
  );
}

if (mcq_score > 0 && mcq_score <= 1) mcq_score = mcq_score * 100;
mcq_score = Math.round(mcq_score * 100) / 100;

return [{
  json: {
    email: input.email,
    testScheduleId: input.testScheduleId,
    mcq_score,
    score_field,
    mcq_raw: candidate
  }
}];

