const mcq = $('Extract MCQ Score').first().json;
const build = $('Build Evaluation').first().json;
const input = $('Normalize Input').first().json;

const SCHEDULE_ROUND_MAP = {
  '6a33a3a95f1bbf5aec52f319': 'round_1'
};

function recommendationFor(score, allRoundsPassed) {
  if (!allRoundsPassed) return 'Not Recommended';
  if (score >= 80) return 'Strong Recommend';
  if (score >= 65) return 'Recommend';
  if (score >= 50) return 'Borderline';
  return 'Not Recommended';
}

const prompting_combined_score = Number(build.combined_score);
if (Number.isNaN(prompting_combined_score)) {
  throw new Error('Build evaluation missing combined_score. Raw: ' + JSON.stringify(build).slice(0, 500));
}

const mcq_score = Number(mcq.mcq_score);
const mcq_weighted = Math.round(0.40 * mcq_score * 100) / 100;
const prompting_weighted = Math.round(0.60 * prompting_combined_score * 100) / 100;
const round_score = Math.round((mcq_weighted + prompting_weighted) * 100) / 100;

const pass_threshold = Number(input.pass_threshold ?? 50);
const round_passed = round_score >= pass_threshold;
const round_status = round_passed ? 'pass' : 'fail';

const roundId = input.round || SCHEDULE_ROUND_MAP[input.testScheduleId] || 'round_1';

const current_round = {
  round: roundId,
  testScheduleId: input.testScheduleId,
  mcq_score,
  mcq_weighted,
  prompting_combined_score,
  prompting_weighted,
  round_score,
  prompt_score: build.prompt_score,
  output_score: build.output_score,
  pass_threshold,
  passed: round_passed,
  status: round_status,
  evaluation_id: build.evaluation_id,
  problem_type: build.problem_type
};

const previous = Array.isArray(input.previous_rounds) ? input.previous_rounds : [];
const otherRounds = previous.filter((r) => r.round !== roundId);
const round_scores = [...otherRounds, current_round];

const overall_score = Math.round(
  round_scores.reduce((sum, r) => sum + Number(r.round_score || 0), 0) / round_scores.length * 100
) / 100;

const rounds_passed = round_scores.filter((r) => r.passed === true || r.status === 'pass').length;
const rounds_failed = round_scores.length - rounds_passed;
const all_rounds_passed = rounds_failed === 0;

const overall_pass_threshold = Number(input.overall_pass_threshold ?? 50);
const overall_passed = overall_score >= overall_pass_threshold && all_rounds_passed;
const overall_status = overall_passed ? 'pass' : 'fail';

const recommendation = recommendationFor(overall_score, all_rounds_passed);

return [{
  json: {
    email: input.email,
    name: input.name || null,
    candidate: {
      email: input.email,
      name: input.name || null
    },
    current_round,
    round_scores,
    round_summary: round_scores.map((r) => ({
      round: r.round,
      round_score: r.round_score,
      mcq_score: r.mcq_score,
      prompting_combined_score: r.prompting_combined_score,
      status: r.status,
      passed: r.passed === true || r.status === 'pass'
    })),
    overall: {
      score: overall_score,
      status: overall_status,
      passed: overall_passed,
      pass_threshold: overall_pass_threshold,
      rounds_completed: round_scores.length,
      rounds_passed,
      rounds_failed
    },
    recommendation,
    ranking: {
      note: 'Sort all candidates by overall.score descending for leaderboard rank',
      sort_key: 'overall.score'
    },
    final_score: round_score,
    status: round_status,
    passed: round_passed,
    pass_threshold,
    mcq_score,
    mcq_weighted,
    prompting_combined_score,
    prompting_weighted,
    evaluation_id: build.evaluation_id,
    problem_type: build.problem_type,
    breakdown: {
      mcq_pct: 40,
      prompting_pct: 60,
      formula: 'round_score = (0.40 x mcq) + (0.60 x prompting)',
      overall_formula: 'average of all round_score values',
      pass_rule: 'round pass if round_score >= pass_threshold; overall pass if all rounds pass and overall.score >= overall_pass_threshold'
    }
  }
}];
